import React from "react";
import { useParams, Link } from "react-router-dom";
import { motion } from "framer-motion";
import { useInView } from "react-intersection-observer";
import { CheckCircle2, ArrowRight, Settings, Ruler, Clock } from "lucide-react";
import PageBanner from "../components/PageBanner";
import { servicePages } from "../data/pageData";

const ServiceDetailPage = () => {
  const { slug } = useParams();
  const data = servicePages[slug];
  const [ref1, inView1] = useInView({ triggerOnce: true, threshold: 0.1 });
  const [ref2, inView2] = useInView({ triggerOnce: true, threshold: 0.1 });
  const [ref3, inView3] = useInView({ triggerOnce: true, threshold: 0.1 });

  if (!data) {
    return (
      <div className="inner-section" style={{ textAlign: 'center', padding: '120px 24px' }}>
        <h2>Service Not Found</h2>
        <p>The requested service page does not exist.</p>
        <Link to="/services" className="btn-primary" style={{ marginTop: 24, display: 'inline-flex' }}>View All Services</Link>
      </div>
    );
  }

  return (
    <>
      <PageBanner
        title={data.heading}
        subtitle={data.subheading}
        image={data.heroImage}
        breadcrumbs={[
          { label: "Services", link: "/services" },
          { label: data.heading }
        ]}
      />

      {/* Intro + Content */}
      <section className="inner-section" ref={ref1}>
        <div className="inner-container">
          <motion.div className="sd-intro" initial={{ opacity: 0, y: 30 }} animate={inView1 ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6 }}>
            <p className="sd-intro-text">{data.intro}</p>
          </motion.div>
          <div className="sd-content-grid">
            <div className="sd-content-main">
              {data.sections.map((sec, i) => (
                <motion.div key={i} className="sd-section" initial={{ opacity: 0, y: 20 }}
                  animate={inView1 ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.5, delay: 0.1 + i * 0.1 }}>
                  <h3>{sec.title}</h3>
                  <p>{sec.content}</p>
                </motion.div>
              ))}
            </div>
            <div className="sd-sidebar">
              <div className="sd-sidebar-card">
                <h4><Settings size={20} /> Technical Specifications</h4>
                <ul className="sd-specs-list">
                  {data.specs.map((sp, i) => (
                    <li key={i}><span className="spec-label">{sp.label}</span><span className="spec-value">{sp.value}</span></li>
                  ))}
                </ul>
              </div>
              <div className="sd-sidebar-card accent">
                <h4>Need a Quote?</h4>
                <p>Upload your 3D model and get an instant quote for {data.heading}.</p>
                <Link to="/contact" className="btn-primary" style={{ width: '100%', justifyContent: 'center' }}>
                  Get Free Quote <ArrowRight size={16} />
                </Link>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Materials */}
      <section className="inner-section bg-light" ref={ref2}>
        <div className="inner-container">
          <motion.div initial={{ opacity: 0, y: 30 }} animate={inView2 ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6 }}>
            <span className="section-subtitle">{slug === 'product-development' ? 'Our Capabilities' : 'Materials & Options'}</span>
            <h2 className="section-title">{slug === 'product-development' ? 'Development Capabilities' : 'Available Materials'}</h2>
            <div className="section-line" />
          </motion.div>
          <div className="materials-grid">
            {data.materials.map((mat, i) => (
              <motion.div key={i} className="material-card" initial={{ opacity: 0, y: 20 }}
                animate={inView2 ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.4, delay: i * 0.08 }}>
                <h4>{mat.name}</h4>
                <p>{mat.desc}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Advantages */}
      <section className="inner-section bg-dark" ref={ref3}>
        <div className="inner-container">
          <motion.div initial={{ opacity: 0, y: 30 }} animate={inView3 ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.6 }}>
            <span className="section-subtitle light">Why Choose Us</span>
            <h2 className="section-title light">Advantages of {data.heading}</h2>
            <div className="section-line" />
          </motion.div>
          <div className="advantages-grid">
            {data.advantages.map((adv, i) => (
              <motion.div key={i} className="advantage-item" initial={{ opacity: 0, x: -20 }}
                animate={inView3 ? { opacity: 1, x: 0 } : {}} transition={{ duration: 0.4, delay: i * 0.1 }}>
                <CheckCircle2 size={22} />
                <span>{adv}</span>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="cta-section">
        <div className="cta-inner">
          <h2 className="cta-title">Ready to Start Your {data.heading} Project?</h2>
          <p className="cta-desc">Upload your design or describe your requirements — our Bangalore team will provide a free quote within 2 hours.</p>
          <Link to="/contact" className="btn-primary">Get a Free Quote <ArrowRight size={18} /></Link>
        </div>
      </section>
    </>
  );
};

export default ServiceDetailPage;
