import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import { useInView } from "react-intersection-observer";
import axios from "axios";
import {
  ArrowRight,
  Send,
  MapPin,
  Phone,
  Mail,
  Clock,
  Facebook,
  Twitter,
  Instagram,
  Linkedin,
  ChevronUp,
} from "lucide-react";
import {
  projects as mockProjects,
  blogPosts as mockBlogPosts,
  trustedBy,
  companyInfo,
  footerData,
} from "../data/mockData";

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
const API = `${BACKEND_URL}/api`;

/* ===== PROJECTS SECTION ===== */
export const ProjectsSection = () => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.1 });
  const [projects, setProjects] = useState(mockProjects);

  useEffect(() => {
    axios.get(`${API}/projects`).then(res => {
      if (res.data && res.data.length > 0) setProjects(res.data);
    }).catch(() => {});
  }, []);
  return (
    <section id="projects" className="projects-section" ref={ref}>
      <div className="projects-inner">
        <motion.div
          className="projects-header"
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="projects-title">Our Latest Projects</h2>
          <div className="section-line" />
          <p className="projects-desc">
            From medical devices to architectural scale models, our portfolio
            showcases the diverse capabilities of 3D Printzkart's additive
            manufacturing expertise in Bangalore.
          </p>
          <Link to="/projects" className="btn-outline-dark">ALL PROJECTS</Link>
        </motion.div>
        <div className="projects-grid">
          {projects.map((project, i) => (
            <motion.div
              key={project.id}
              className="project-card"
              initial={{ opacity: 0, y: 30 }}
              animate={inView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.5, delay: 0.1 + i * 0.1 }}
            >
              <div className="project-image">
                <img
                  src={project.image}
                  alt={project.title}
                  loading="lazy"
                />
                <div className="project-overlay">
                  <span className="project-category">{project.category}</span>
                </div>
              </div>
              <div className="project-info">
                <h3>{project.title}</h3>
                <Link to="/projects" className="project-link">
                  VIEW MORE <ArrowRight size={14} />
                </Link>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

