/* ===== CONTACT SECTION ===== */
export const ContactSection = () => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.1 });
  const [formData, setFormData] = useState({
    name: "", email: "", phone: "", service: "", message: "",
  });
  const [submitted, setSubmitted] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setErrorMsg("");
    try {
      await axios.post(`${API}/quotes`, formData);
      setSubmitted(true);
      setFormData({ name: "", email: "", phone: "", service: "", message: "" });
      setTimeout(() => setSubmitted(false), 4000);
    } catch (err) {
      setErrorMsg("Something went wrong. Please try again or call us directly.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section id="contact" className="contact-section" ref={ref}>
      <div className="contact-inner">
        <motion.div
          className="contact-info"
          initial={{ opacity: 0, x: -30 }}
          animate={inView ? { opacity: 1, x: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="contact-title">Get In Touch</h2>
          <div className="section-line light-line" />
          <p className="contact-desc">
            Ready to bring your designs to life? Contact us for a free consultation and quote on your 3D printing project.
          </p>
          <div className="contact-details">
            <div className="contact-detail-item">
              <MapPin size={20} />
              <div>
                <strong>Our Office</strong>
                <p>{companyInfo.address}</p>
              </div>
            </div>
            <div className="contact-detail-item">
              <Phone size={20} />
              <div>
                <strong>Call Us</strong>
                <p>{companyInfo.phone}</p>
              </div>
            </div>
            <div className="contact-detail-item">
              <Mail size={20} />
              <div>
                <strong>Email Us</strong>
                <p>{companyInfo.email}</p>
              </div>
            </div>
            <div className="contact-detail-item">
              <Clock size={20} />
              <div>
                <strong>Working Hours</strong>
                <p>{companyInfo.workingHours}</p>
              </div>
            </div>
          </div>
        </motion.div>
        <motion.div
          className="contact-form-wrap"
          initial={{ opacity: 0, x: 30 }}
          animate={inView ? { opacity: 1, x: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.2 }}
        >
          <h3>Request a Quote</h3>
          {submitted && (
            <div className="form-success">Thank you! We'll get back to you within 24 hours.</div>
          )}
          {errorMsg && (
            <div className="form-success" style={{ borderColor: '#e74c3c', background: 'rgba(231,76,60,0.15)' }}>{errorMsg}</div>
          )}
          <form onSubmit={handleSubmit}>
            <div className="form-row">
              <input
                type="text"
                placeholder="Your Name *"
                required
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />
              <input
                type="email"
                placeholder="Your Email *"
                required
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />
            </div>
            <div className="form-row">
              <input
                type="tel"
                placeholder="Phone Number *"
                required
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
              />
              <select
                value={formData.service}
                onChange={(e) => setFormData({ ...formData, service: e.target.value })}
                required
              >
                <option value="">Select Service *</option>
                <option value="fdm">FDM 3D Printing</option>
                <option value="sla">SLA 3D Printing</option>
                <option value="sls">SLS 3D Printing</option>
                <option value="dmls">DMLS Metal Printing</option>
                <option value="product">Product Development</option>
                <option value="other">Other</option>
              </select>
            </div>
            <textarea
              placeholder="Tell us about your project..."
              rows={4}
              value={formData.message}
              onChange={(e) => setFormData({ ...formData, message: e.target.value })}
            />
            <button type="submit" className="btn-primary" disabled={submitting}>
              <Send size={16} />
              {submitting ? "Sending..." : "Send Message"}
            </button>
          </form>
        </motion.div>
      </div>
    </section>
  );
};

